import { jsx, Fragment } from 'react/jsx-runtime';
import { useEffect } from 'react';
import { useTreeContext } from '../TreeContext.js';

const TreeNodesWrapper = ({ children, size, multiselect, amount, expandOnArrow, onExpandCallback, }) => {
    const { changeTreeParams } = useTreeContext();
    useEffect(() => {
        const params = {
            amount: amount,
            size: size,
            multiselect: multiselect,
            expandOnArrow: expandOnArrow,
            onExpandCallback: onExpandCallback,
        };
        changeTreeParams(params); // пишем параметры в контекст ради удобства
    }, [size, multiselect, amount, expandOnArrow, onExpandCallback]);
    return jsx(Fragment, { children: children });
};

export { TreeNodesWrapper };
